namespace {
static inline int64_t FloorDiv(int64_t a, int64_t b) {
    return a / b;
}

static inline int64_t ClampNonNegative(int64_t x) {
    return x > 0 ? x : 0;
}
}

namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    AveragePooling3dCustomTilingData tiling;

    const gert::Shape *in_shape = context->GetInputShape(0);
    const std::vector<int64_t> &dims = in_shape->GetOriginShape().GetDims();
    // Expect NCDHW
    int64_t N = 1, C = 1, D = 1, H = 1, W = 1;
    if (dims.size() == 5) {
        N = dims[0]; C = dims[1]; D = dims[2]; H = dims[3]; W = dims[4];
    } else if (dims.size() == 3) {
        // Fallback NDH (treat as N=1,C=1)
        D = dims[0]; H = dims[1]; W = dims[2];
    } else {
        // Unsupported; fall back to scalar shape
        D = in_shape->GetShapeSize();
        H = 1; W = 1;
    }

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *kernelPtr = attrs->GetAttrPointer<int32_t>(0);
    const int32_t *stridePtr = attrs->GetAttrPointer<int32_t>(1);
    const int32_t *padPtr    = attrs->GetAttrPointer<int32_t>(2);
    const bool *countPadPtr  = attrs->GetAttrPointer<bool>(3);

    int64_t kD = static_cast<int64_t>(*kernelPtr);
    int64_t kH = static_cast<int64_t>(*kernelPtr);
    int64_t kW = static_cast<int64_t>(*kernelPtr);

    int64_t sD = (stridePtr && *stridePtr > 0) ? static_cast<int64_t>(*stridePtr) : kD;
    int64_t sH = (stridePtr && *stridePtr > 0) ? static_cast<int64_t>(*stridePtr) : kH;
    int64_t sW = (stridePtr && *stridePtr > 0) ? static_cast<int64_t>(*stridePtr) : kW;

    int64_t pD = padPtr ? static_cast<int64_t>(*padPtr) : 0;
    int64_t pH = padPtr ? static_cast<int64_t>(*padPtr) : 0;
    int64_t pW = padPtr ? static_cast<int64_t>(*padPtr) : 0;

    bool countIncludePad = (countPadPtr != nullptr) ? *countPadPtr : false;

    int64_t outD = ClampNonNegative(FloorDiv((D + 2 * pD - kD), sD) + 1);
    int64_t outH = ClampNonNegative(FloorDiv((H + 2 * pH - kH), sH) + 1);
    int64_t outW = ClampNonNegative(FloorDiv((W + 2 * pW - kW), sW) + 1);

    uint64_t totalOut = static_cast<uint64_t>(N) * static_cast<uint64_t>(C) *
                        static_cast<uint64_t>(outD) * static_cast<uint64_t>(outH) * static_cast<uint64_t>(outW);

    uint32_t blockDim = static_cast<uint32_t>(totalOut < 32 ? (totalOut == 0 ? 1 : totalOut) : 32);
    if (blockDim == 0) blockDim = 1;
    context->SetBlockDim(blockDim);

    tiling.set_n(static_cast<uint32_t>(N));
    tiling.set_c(static_cast<uint32_t>(C));
    tiling.set_d(static_cast<uint32_t>(D));
    tiling.set_h(static_cast<uint32_t>(H));
    tiling.set_w(static_cast<uint32_t>(W));
    tiling.set_outD(static_cast<uint32_t>(outD));
    tiling.set_outH(static_cast<uint32_t>(outH));
    tiling.set_outW(static_cast<uint32_t>(outW));
    tiling.set_kD(static_cast<uint32_t>(kD));
    tiling.set_kH(static_cast<uint32_t>(kH));
    tiling.set_kW(static_cast<uint32_t>(kW));
    tiling.set_sD(static_cast<uint32_t>(sD));
    tiling.set_sH(static_cast<uint32_t>(sH));
    tiling.set_sW(static_cast<uint32_t>(sW));
    tiling.set_pD(static_cast<uint32_t>(pD));
    tiling.set_pH(static_cast<uint32_t>(pH));
    tiling.set_pW(static_cast<uint32_t>(pW));
    tiling.set_totalOut(static_cast<uint32_t>(totalOut));
    tiling.set_blockDim(blockDim);
    tiling.set_countIncludePad(static_cast<uint8_t>(countIncludePad ? 1 : 0));

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspaceSizes = context->GetWorkspaceSizes(1);
    workspaceSizes[0] = 0;
    return ge::GRAPH_SUCCESS;
}

